export type SessionType = "talk" | "keynote" | "meal" | "break" | "social" | "poster";

export interface Session {
  id: string;
  day: "thursday" | "friday" | "saturday";
  date: string; // ISO date
  room: string;
  startTime: string | null; // 24h HH:MM
  endTime: string | null;
  title: string;
  presenters?: string;
  type: SessionType;
  description?: string;
  objectives?: string[];
  note?: string;
}

